// packages/mcp/dist/tools/reap-orphans.js
function registerReapOrphans(server) {
  server.tool("reap-orphans", "Terminate orphaned LinkedHelper account-instance processes. Dry-run by default \u2014 set confirm: true to actually kill processes. Never touches connectable instances, the launcher, or helper children of live parents.", {
    confirm: external_exports.boolean().optional().describe("Set to true to actually terminate orphans. Omit or set false for a dry-run that shows what would be killed.")
  }, async ({ confirm }) => {
    try {
      let liveInstances = await scanRunningInstances(), orphans = await scanOrphans(liveInstances);
      if (orphans.length === 0)
        return mcpSuccess("No orphaned processes to reap.");
      if (!confirm)
        return mcpSuccess(`Dry-run: would terminate ${String(orphans.length)} orphan(s):
${JSON.stringify(orphans, null, 2)}

Set confirm: true to proceed.`);
      let results = await reapOrphans(orphans, !0), killed = results.filter((r) => r.action === "killed").length, skipped = results.filter((r) => r.action === "skipped").length;
      return killed === 0 && skipped > 0 ? mcpError(`Failed to terminate all ${String(skipped)} orphan(s):
${JSON.stringify(results, null, 2)}`) : mcpSuccess(`Terminated ${String(killed)} orphan(s)${skipped > 0 ? `, ${String(skipped)} failed` : ""}:
${JSON.stringify(results, null, 2)}`);
    } catch (error51) {
      return mcpCatchAll(error51, "Failed to reap orphans");
    }
  });
}

