// packages/mcp/dist/server.js
var require3 = createRequire2(import.meta.url), { name, version: version3 } = require3("../package.json");
function createServer() {
  let server = new McpServer({ name, version: version3 });
  return registerAllTools(server), server;
}

// packages/mcp/dist/stdio.js
async function runStdioServer() {
  let server = createServer(), transport = new StdioServerTransport();
  try {
    await server.connect(transport);
  } catch (error51) {
    let message = errorMessage(error51);
    process.stderr.write(`Failed to start MCP server: ${message}
`), process.exit(1);
  }
  process.stderr.write(`lhremote MCP server running on stdio
`);
  function shutdown() {
    server.close().catch((error51) => {
      let message = errorMessage(error51);
      process.stderr.write(`Error during shutdown: ${message}
`);
    }).finally(() => {
      process.exit(0);
    });
  }
  process.on("SIGINT", shutdown), process.on("SIGTERM", shutdown);
}

// packages/lhremote/dist/cli.js
